1	import { Image, View } from "@tarojs/components";
2	import { memo, useMemo, useState } from "react";
3	import { ICON_PATHS, PLACEHOLDER } from "./iconPaths";
4	
5	export type IconName =
6	  | "dumbbell" | "book-open" | "sparkles" | "briefcase"
7	  | "brain" | "landmark" | "globe" | "home"
8	  | "target" | "palette" | "music" | "pen"
9	  | "lotus" | "runner" | "heart-pulse" | "laptop"
10	  | "clipboard" | "film" | "message-circle" | "compass"
11	  | "microscope" | "bar-chart" | "lightbulb" | "star"
12	  | "package" | "bot" | "award" | "clipboard-list"
13	  | "check" | "x"
14	  | "mood-1" | "mood-2" | "mood-3" | "mood-4" | "mood-5";
15	
16	export type IconColor = "primary" | "secondary" | "accent" | "muted" | "faded";
17	
18	export interface IconProps {
19	  name: IconName;
20	  size?: number;
21	  color?: IconColor;
22	}
23	
24	const COLOR_MAP: Record<IconColor, string> = {
25	  primary: "#e8e0d6",
26	  secondary: "#a89f92",
27	  accent: "#c4843e",
28	  muted: "#7a7268",
29	  faded: "#4a4540",
30	};
31	
32	/** 纯 JS base64 编码（ASCII 安全，不依赖 btoa / TextEncoder） */
33	function toBase64(str: string): string {
34	  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
35	  const bytes: number[] = [];
36	  for (let i = 0; i < str.length; i++) {
37	    bytes.push(str.charCodeAt(i));
38	  }
39	
40	  let result = "";
41	  for (let i = 0; i < bytes.length; i += 3) {
42	    const a = bytes[i];
43	    const b = i + 1 < bytes.length ? bytes[i + 1] : null;
44	    const c = i + 2 < bytes.length ? bytes[i + 2] : null;
45	
46	    result += chars[a >> 2];
47	    result += chars[((a & 3) << 4) | (b !== null ? b >> 4 : 0)];
48	
49	    if (b === null) {
50	      result += "==";
51	    } else {
52	      result += chars[((b & 15) << 2) | (c !== null ? c >> 6 : 0)];
53	      if (c === null) {
54	        result += "=";
55	      } else {
56	        result += chars[c & 63];
57	      }
58	    }
59	  }
60	  return result;
61	}
62	
63	/** 根据图标定义和颜色生成 base64 data URI */
64	function buildSvgSrc(name: IconName, colorHex: string): string {
65	  const icon = ICON_PATHS[name];
66	  if (!icon) return "";
67	
68	  // 替换路径中的占位符和 currentColor（Palette 等图标用）
69	  const paths = icon.paths
70	    .replace(new RegExp(PLACEHOLDER, "g"), colorHex)
71	    .replace(/currentColor/g, colorHex);
72	
73	  // 确定 fill 值：有定义则用（含 {{COLOR}} 替换），否则默认 "none"
74	  const fillValue = icon.fill
75	    ? icon.fill.replace(new RegExp(PLACEHOLDER, "g"), colorHex)
76	    : "none";
77	
78	  const parts: string[] = [
79	    '<svg xmlns="http://www.w3.org/2000/svg"',
80	    ' width="24" height="24" viewBox="0 0 24 24"',
81	    ' fill="' + fillValue + '"',
82	    ' stroke="' + colorHex + '"',
83	    ' stroke-width="2"',
84	    ' stroke-linecap="round"',
85	    ' stroke-linejoin="round"',
86	  ];
87	
88	  if (icon.fillOpacity) {
89	    parts.push(' fill-opacity="' + icon.fillOpacity + '"');
90	  }
91	
92	  parts.push(">", paths, "</svg>");
93	
94	  return "data:image/svg+xml;base64," + toBase64(parts.join(""));
95	}
96	
97	/** 兜底：用 star 作为 fallback */
98	const FALLBACK_NAME: IconName = "star";
99	
100	function Icon({ name, size = 48, color = "primary" }: IconProps) {
101	  const colorHex = COLOR_MAP[color];
102	  const [hasError, setHasError] = useState(false);
103	
104	  const svgSrc = useMemo(() => {
105	    return buildSvgSrc(name, colorHex) || buildSvgSrc(FALLBACK_NAME, colorHex);
106	  }, [name, colorHex]);
107	
108	  if (hasError) {
109	    return (
110	      <View
111	        style={{
112	          width: size + "rpx",
113	          height: size + "rpx",
114	          borderRadius: "50%",
115	          backgroundColor: colorHex,
116	        }}
117	      />
118	    );
119	  }
120	
121	  return (
122	    <Image
123	      src={svgSrc}
124	      mode="aspectFit"
125	      style={{ width: size + "rpx", height: size + "rpx" }}
126	      onError={() => setHasError(true)}
127	    />
128	  );
129	}
130	
131	export default memo(Icon);
