1	import Taro from "@tarojs/taro";
2	
3	const API_BASE = "https://unstirred-clang-peddling.ngrok-free.dev";
4	
5	export async function apiFetch(path: string, options?: RequestInit) {
6	  const url = `${API_BASE}${path}`;
7	  const res = await Taro.request({
8	    url,
9	    method: (options?.method as any) || "GET",
10	    data: options?.body ? JSON.parse(options.body as string) : undefined,
11	    header: {
12	      "Content-Type": "application/json",
13	      "ngrok-skip-browser-warning": "1",
14	    },
15	    timeout: 15000,
16	  });
17	  if (res.statusCode >= 400) throw new Error(`API error: ${res.statusCode}`);
18	  return res.data;
19	}
