1	import { useState } from "react";
2	import { View, Text, Input, Picker } from "@tarojs/components";
3	import { useDidShow, showModal, showToast } from "@tarojs/taro";
4	import { apiFetch } from "../../lib";
5	import { getDomains, saveDomains, Domain, UNCATEGORIZED } from "../../lib/domains";
6	import Icon, { IconName } from "../../components/Icon";
7	import "./index.scss";
8	
9	const FREQ_LABELS: Record<string, string> = { daily: "每日", weekly: "每周", weekday: "工作日" };
10	
11	const DOMAIN_ICON_OPTIONS: IconName[] = [
12	  "dumbbell", "book-open", "sparkles", "briefcase", "brain", "landmark", "globe", "home",
13	  "target", "palette", "music", "pen", "lotus", "runner", "heart-pulse", "laptop",
14	  "clipboard", "film", "message-circle", "compass", "microscope", "bar-chart", "lightbulb", "star",
15	];
16	
17	const COLOR_OPTIONS = [
18	  "#ef4444", "#3b82f6", "#ec4899", "#f59e0b",
19	  "#8b5cf6", "#10b981", "#06b6d4", "#78716c",
20	];
21	
22	interface Habit {
23	  id: string;
24	  title: string;
25	  description: string | null;
26	  domainId: string;
27	  unit: string;
28	  targetValue: number;
29	  frequency: string;
30	  isActive: boolean;
31	}
32	
33	export default function HabitsPage() {
34	  const [habits, setHabits] = useState<Habit[]>([]);
35	  const [loading, setLoading] = useState(true);
36	  const [showForm, setShowForm] = useState(false);
37	  const [editId, setEditId] = useState<string | null>(null);
38	  const [form, setForm] = useState({
39	    title: "", description: "", domainIdx: 0, unit: "次",
40	    targetValue: 1, frequency: "daily",
41	  });
42	
43	  // Domain management state
44	  const [showDomainManager, setShowDomainManager] = useState(false);
45	  const [domainManagerView, setDomainManagerView] = useState<"list" | "new" | "edit">("list");
46	  const [domainForm, setDomainForm] = useState<Domain>({ name: "", icon: "dumbbell", color: "#ef4444" });
47	  const [editingDomainName, setEditingDomainName] = useState<string | null>(null);
48	  const [saving, setSaving] = useState(false);
49	  const [formDirty, setFormDirty] = useState(false);
50	
51	  useDidShow(() => { fetchHabits(); });
52	
53	  async function fetchHabits() {
54	    try {
55	      setHabits(await apiFetch("/api/habits"));
56	    } catch (e: any) {
57	      console.error("[fetchHabits]", e);
58	      showToast({ title: "获取习惯列表失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
59	    }
60	    setLoading(false);
61	  }
62	
63	  function openNew() {
64	    setEditId(null);
65	    setForm({ title: "", description: "", domainIdx: 0, unit: "次", targetValue: 1, frequency: "daily" });
66	    setFormDirty(false);
67	    setShowForm(true);
68	  }
69	
70	  function openEdit(h: Habit) {
71	    setEditId(h.id);
72	    const domains = getDomains();
73	    const idx = domains.findIndex(d => d.name === h.domainId);
74	    setForm({
75	      title: h.title,
76	      description: h.description || "",
77	      domainIdx: idx >= 0 ? idx : domains.length - 1,
78	      unit: h.unit,
79	      targetValue: h.targetValue,
80	      frequency: h.frequency,
81	    });
82	    setFormDirty(false);
83	    setShowForm(true);
84	  }
85	
86	  async function handleSave() {
87	    const domains = getDomains();
88	    if (form.domainIdx < 0 || form.domainIdx >= domains.length) {
89	      showToast({ title: "领域索引无效", icon: "none" });
90	      return;
91	    }
92	    setSaving(true);
93	    try {
94	      const body = { ...form, domainId: domains[form.domainIdx].name };
95	      if (editId) {
96	        await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
97	      } else {
98	        await apiFetch("/api/habits", { method: "POST", body: JSON.stringify(body) });
99	      }
100	      setShowForm(false);
101	      setFormDirty(false);
102	      fetchHabits();
103	    } catch (e: any) {
104	      console.error("[handleSave]", e);
105	      showToast({ title: "保存习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
106	    } finally {
107	      setSaving(false);
108	    }
109	  }
110	
111	  async function handleCloseForm() {
112	    if (formDirty) {
113	      const res = await showModal({ title: "确认关闭", content: "当前填写的内容尚未保存，确定要关闭吗？" });
114	      if (!res.confirm) return;
115	    }
116	    setShowForm(false);
117	    setFormDirty(false);
118	  }
119	
120	  async function deleteHabit(id: string) {
121	    try {
122	      await apiFetch("/api/habits", { method: "DELETE", body: JSON.stringify({ id }) });
123	      fetchHabits();
124	    } catch (e: any) {
125	      console.error("[deleteHabit]", e);
126	      showToast({ title: "删除习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
127	    }
128	  }
129	
130	  async function toggleActive(id: string, current: boolean) {
131	    try {
132	      await apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id, isActive: !current }) });
133	      fetchHabits();
134	    } catch (e: any) {
135	      console.error("[toggleActive]", e);
136	      showToast({ title: "操作失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
137	    }
138	  }
139	
140	  // ---- Domain management handlers ----
141	
142	  function openDomainManager() {
143	    setShowForm(false);
144	    setDomainManagerView("list");
145	    setDomainForm({ name: "", icon: "dumbbell", color: "#ef4444" });
146	    setEditingDomainName(null);
147	    setShowDomainManager(true);
148	  }
149	
150	  function openNewDomain() {
151	    setDomainForm({ name: "", icon: "dumbbell", color: "#ef4444" });
152	    setDomainManagerView("new");
153	  }
154	
155	  function openEditDomain(domain: Domain) {
156	    setEditingDomainName(domain.name);
157	    setDomainForm({ name: domain.name, icon: domain.icon, color: domain.color });
158	    setDomainManagerView("edit");
159	  }
160	
161	  async function handleDomainSave() {
162	    const name = domainForm.name.trim();
163	    if (!name) return;
164	
165	    const userDomains = getDomains().filter(d => d.name !== UNCATEGORIZED.name);
166	
167	    if (domainManagerView === "new") {
168	      if (userDomains.some(d => d.name === name)) {
169	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
170	        return;
171	      }
172	      userDomains.push({ name, icon: domainForm.icon, color: domainForm.color });
173	    } else if (domainManagerView === "edit") {
174	      const idx = userDomains.findIndex(d => d.name === editingDomainName);
175	      if (idx === -1) return;
176	
177	      if (name !== editingDomainName && userDomains.some(d => d.name === name)) {
178	        showModal({ title: "提示", content: "该领域名称已存在", showCancel: false });
179	        return;
180	      }
181	
182	      const oldName = userDomains[idx].name;
183	      userDomains[idx] = { name, icon: domainForm.icon, color: domainForm.color };
184	
185	      // If domain renamed, update all habits under old name
186	      if (name !== oldName) {
187	        try {
188	          await Promise.all(habits.filter(h => h.domainId === oldName).map(h =>
189	            apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: name }) })
190	          ));
191	          fetchHabits();
192	        } catch (e: any) {
193	          console.error("[handleDomainSave-migrate]", e);
194	          showToast({ title: "迁移习惯失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
195	          return;
196	        }
197	      }
198	    }
199	
200	    saveDomains(userDomains);
201	    setDomainManagerView("list");
202	    setEditingDomainName(null);
203	  }
204	
205	  async function handleDeleteDomain(domain: Domain) {
206	    const count = habits.filter(h => h.domainId === domain.name).length;
207	    const res = await showModal({
208	      title: "删除领域",
209	      content: `确定删除"${domain.name}"吗？其下 ${count} 个习惯将移入"未分类"。`,
210	    });
211	
212	    if (!res.confirm) return;
213	
214	    setSaving(true);
215	    try {
216	      // Move habits to 未分类 first, then delete domain
217	      await Promise.all(habits.filter(h => h.domainId === domain.name).map(h =>
218	        apiFetch("/api/habits", { method: "PUT", body: JSON.stringify({ id: h.id, domainId: UNCATEGORIZED.name }) })
219	      ));
220	
221	      const userDomains = getDomains()
222	        .filter(d => d.name !== UNCATEGORIZED.name && d.name !== domain.name);
223	      saveDomains(userDomains);
224	
225	      fetchHabits();
226	    } catch (e: any) {
227	      console.error("[handleDeleteDomain]", e);
228	      showToast({ title: "删除领域失败: " + (e?.message || e?.errMsg || String(e)), icon: "none" });
229	    } finally {
230	      setSaving(false);
231	    }
232	  }
233	
234	  const domains = getDomains();
235	
236	  return (
237	    <View className="page">
238	      <View className="page-header">
239	        <View>
240	          <Text className="page-title">习惯管理</Text>
241	          <Text className="page-subtitle">管理你的每日修炼清单</Text>
242	        </View>
243	        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
244	      </View>
245	
246	      {domains.map((domain) => {
247	        const domainHabits = habits.filter((h) => h.domainId === domain.name);
248	        return (
249	          <View key={domain.name}>
250	            <View className="domain-title-row">
251	              <Icon name={domain.icon as IconName} size={36} color="accent" />
252	              <Text className="domain-title">{domain.name}</Text>
253	            </View>
254	            {domainHabits.map((habit) => (
255	              <View key={habit.id} className={`habit-card ${!habit.isActive ? "inactive" : ""}`}>
256	                <View className="habit-info">
257	                  <Text className="habit-name">{habit.title}</Text>
258	                  {habit.description && <Text className="habit-desc">{habit.description}</Text>}
259	                  <View className="habit-meta">
260	                    <Text>{FREQ_LABELS[habit.frequency] || habit.frequency}</Text>
261	                    <Text> · </Text>
262	                    <Text>目标 {habit.targetValue}{habit.unit}</Text>
263	                  </View>
264	                </View>
265	                <View className="habit-actions">
266	                  <Text className={`action-btn ${saving ? "disabled" : ""}`} onClick={() => !saving && toggleActive(habit.id, habit.isActive)}>
267	                    {habit.isActive ? "停用" : "启用"}
268	                  </Text>
269	                  <Text className="action-btn" onClick={() => openEdit(habit)}>编辑</Text>
270	                  <Text className={`action-btn danger ${saving ? "disabled" : ""}`} onClick={() => !saving && deleteHabit(habit.id)}>删除</Text>
271	                </View>
272	              </View>
273	            ))}
274	          </View>
275	        );
276	      })}
277	
278	      <View className="domain-manager-entry" onClick={openDomainManager}>
279	        <View className="domain-manager-entry-bar" />
280	        <Text className="domain-manager-entry-text">管理分类</Text>
281	        <Text className="domain-manager-entry-arrow">&#8250;</Text>
282	      </View>
283	
284	      {!loading && habits.length === 0 && (
285	        <View className="empty"><Text>还没有习惯，点右上角 + 开始</Text></View>
286	      )}
287	
288	      {/* ---- Habit Form Modal ---- */}
289	      {showForm && (
290	        <View className="modal-mask" onClick={handleCloseForm}>
291	          <View className="modal" onClick={(e) => e.stopPropagation()}>
292	            <Text className="modal-title">{editId ? "编辑习惯" : "新增习惯"}</Text>
293	
294	            <View className="form-group">
295	              <Text className="form-label">名称</Text>
296	              <Input className="form-input" placeholder="如：晨跑30分钟" value={form.title} onInput={(e) => { setForm({ ...form, title: e.detail.value }); setFormDirty(true); }} />
297	            </View>
298	
299	            <View className="form-group">
300	              <Text className="form-label">描述</Text>
301	              <Input className="form-input" placeholder="具体怎么做" value={form.description} onInput={(e) => { setForm({ ...form, description: e.detail.value }); setFormDirty(true); }} />
302	            </View>
303	
304	            <View className="form-row">
305	              <View className="form-group flex-1">
306	                <Text className="form-label">领域</Text>
307	                <Picker mode="selector" range={domains.map(d => d.name)} value={form.domainIdx} onChange={(e) => { setForm({ ...form, domainIdx: +e.detail.value }); setFormDirty(true); }}>
308	                  <View className="form-picker">
309	                    <Icon name={domains[form.domainIdx].icon as IconName} size={32} color="accent" />
310	                    <Text> {domains[form.domainIdx].name}</Text>
311	                  </View>
312	                </Picker>
313	                <View className="domain-picker-indicator" style={{ backgroundColor: domains[form.domainIdx].color }} />
314	              </View>
315	              <View className="form-group flex-1">
316	                <Text className="form-label">频率</Text>
317	                <Picker mode="selector" range={["每日", "每周", "工作日"]} value={form.frequency === "daily" ? 0 : form.frequency === "weekly" ? 1 : 2} onChange={(e) => { setForm({ ...form, frequency: ["daily", "weekly", "weekday"][+e.detail.value] }); setFormDirty(true); }}>
318	                  <View className="form-picker">{form.frequency === "daily" ? "每日" : form.frequency === "weekly" ? "每周" : "工作日"}</View>
319	                </Picker>
320	              </View>
321	            </View>
322	
323	            <View className="form-row">
324	              <View className="form-group flex-1">
325	                <Text className="form-label">目标值</Text>
326	                <Input className="form-input" type="number" value={String(form.targetValue)} onInput={(e) => { setForm({ ...form, targetValue: +e.detail.value || 1 }); setFormDirty(true); }} />
327	              </View>
328	              <View className="form-group flex-1">
329	                <Text className="form-label">单位</Text>
330	                <Input className="form-input" placeholder="次/分钟/页" value={form.unit} onInput={(e) => { setForm({ ...form, unit: e.detail.value }); setFormDirty(true); }} />
331	              </View>
332	            </View>
333	
334	            <View className="form-buttons">
335	              <View className="btn-cancel" onClick={handleCloseForm}><Text>取消</Text></View>
336	              <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleSave()}><Text>{editId ? "保存" : "添加"}</Text></View>
337	            </View>
338	          </View>
339	        </View>
340	      )}
341	
342	      {/* ---- Domain Manager Modal ---- */}
343	      {showDomainManager && (
344	        <View className="modal-mask" onClick={() => setShowDomainManager(false)}>
345	          <View className="modal" onClick={(e) => e.stopPropagation()}>
346	            <View className="domain-manager-accent" />
347	
348	            {/* List View */}
349	            {domainManagerView === "list" && (
350	              <>
351	                <View className="modal-header-row">
352	                  <Text className="modal-title">管理分类</Text>
353	                  <Text className="modal-add-btn" onClick={openNewDomain}>+ 新增</Text>
354	                </View>
355	
356	                {domains.map((domain) => {
357	                  const isSystem = domain.name === UNCATEGORIZED.name;
358	                  return (
359	                    <View key={domain.name} className="domain-item">
360	                      <View className="domain-item-bar" style={{ backgroundColor: domain.color }} />
361	                      <View className="domain-item-icon">
362	                        <Icon name={domain.icon as IconName} size={36} color="accent" />
363	                      </View>
364	                      <Text className="domain-item-name">{domain.name}</Text>
365	                      {isSystem ? (
366	                        <Text className="domain-item-tag">系统</Text>
367	                      ) : (
368	                        <View className="domain-item-actions">
369	                          <View className="domain-item-action edit" onClick={() => openEditDomain(domain)}>
370	                            <Text>&#9998;</Text>
371	                          </View>
372	                          <View className={`domain-item-action delete${saving ? " disabled" : ""}`} onClick={() => !saving && handleDeleteDomain(domain)}>
373	                            <Text>&#10005;</Text>
374	                          </View>
375	                        </View>
376	                      )}
377	                    </View>
378	                  );
379	                })}
380	
381	                <View className="domain-close-btn" onClick={() => setShowDomainManager(false)}>
382	                  <Text>关闭</Text>
383	                </View>
384	              </>
385	            )}
