    fetchGoals();
    fetchHabits();
  });

  async function fetchGoals() {
    try {
      setGoals(await apiFetch("/api/goals"));
    } catch {
      showToast({ title: "获取目标列表失败", icon: "none" });
    }
    setLoading(false);
  }

  async function fetchHabits() {
    try {
      const data = await apiFetch("/api/habits");
      setHabits(data.map((h: any) => ({ id: h.id, title: h.title, isActive: h.isActive })));
    } catch {
      // non-critical
    }
  }

  function openNew() {
    setEditId(null);
    setForm({ title: "", description: "", startValue: "", targetValue: "", currentValue: "", unit: "次", deadline: "", linkedHabitIds: [] });
    setFormDirty(false);
    setShowForm(true);
    setShowAI(false);
    setAiSuggestions([]);
  }

  function openEdit(g: Goal) {
    setEditId(g.id);
    setForm({
      title: g.title,
      description: g.description || "",
      startValue: String(g.startValue),
      targetValue: String(g.targetValue),
      currentValue: String(g.currentValue),
      unit: g.unit,
      deadline: g.deadline || "",
      linkedHabitIds: [...g.linkedHabitIds]
    });
    setFormDirty(false);
    setShowForm(true);
    setShowAI(false);
    setAiSuggestions([]);
  }

  function validateForm(): boolean {
    if (!form.title.trim()) { showToast({ title: "请输入目标名称", icon: "none" }); return false; }
    const sv = parseFloat(form.startValue);
    const tv = parseFloat(form.targetValue);
    if (isNaN(sv)) { showToast({ title: "请输入有效的起始值", icon: "none" }); return false; }
    if (isNaN(tv)) { showToast({ title: "请输入有效的目标值", icon: "none" }); return false; }
    if (tv === sv) { showToast({ title: "目标值不能等于起始值", icon: "none" }); return false; }
    if (!form.unit.trim()) { showToast({ title: "请输入单位", icon: "none" }); return false; }
    return true;
  }

  async function handleSave() {
    if (!validateForm()) return;
    setSaving(true);
    try {
      const body: any = {
        title: form.title.trim(),
        description: form.description.trim() || null,
        startValue: parseFloat(form.startValue),
        targetValue: parseFloat(form.targetValue),
        unit: form.unit.trim(),
        linkedHabitIds: form.linkedHabitIds
      };
      const cv = parseFloat(form.currentValue);
      if (!isNaN(cv)) body.currentValue = cv;
      if (form.deadline) body.deadline = form.deadline;

      if (editId) {
        await apiFetch("/api/goals", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
      } else {
        await apiFetch("/api/goals", { method: "POST", body: JSON.stringify(body) });
      }
      setShowForm(false);
      setFormDirty(false);
      fetchGoals();
    } catch {
      showToast({ title: "保存目标失败", icon: "none" });
    } finally {
      setSaving(false);
    }
  }

  async function handleCloseForm() {
    if (formDirty) {
      const res = await showModal({ title: "确认关闭", content: "当前填写的内容尚未保存，确定要关闭吗？" });
      if (!res.confirm) return;
    }
    setShowForm(false);
  }

  async function deleteGoal(id: string) {
    const res = await showModal({ title: "确认删除", content: "删除后无法恢复，确定要删除此目标吗？" });
    if (!res.confirm) return;
    try {
      await apiFetch("/api/goals", { method: "DELETE", body: JSON.stringify({ id }) });
      fetchGoals();
    } catch {
      showToast({ title: "删除目标失败", icon: "none" });
    }
  }

  async function loadAIRecommendations() {
    setAiLoading(true);
    try {
      const data = await apiFetch("/api/goals/ai/suggestions?type=recommend");
      setAiSuggestions(data || []);
      setShowAI(true);
    } catch {
      showToast({ title: "获取AI推荐失败", icon: "none" });
    }
    setAiLoading(false);
  }

  function applyAISuggestion(s: AISuggestion) {
    setForm({
      title: s.title,
      description: s.description,
      startValue: String(s.suggestedStartValue),
      targetValue: String(s.suggestedTargetValue),
      currentValue: String(s.suggestedStartValue),
      unit: s.unit,
      deadline: "",
      linkedHabitIds: []
    });
    setShowAI(false);
    setFormDirty(true);
  }

  function toggleLinkedHabit(habitId: string) {
    setForm(prev => ({
      ...prev,
      linkedHabitIds: prev.linkedHabitIds.includes(habitId)
        ? prev.linkedHabitIds.filter(id => id !== habitId)
        : [...prev.linkedHabitIds, habitId]
    }));
    setFormDirty(true);
  }

  const activeGoals = goals.filter(g => !g.isArchived && g.progress < 1);
  const achievedGoals = goals.filter(g => g.isArchived || g.progress >= 1);

  function renderGoalCard(g: Goal) {
    const isAchieved = g.progress >= 1;
    const progressPct = Math.min(Math.round(g.progress * 100), 100);

    return (
      <View key={g.id} className={`goal-card ${isAchieved ? "achieved" : ""}`}>
        <View className="goal-card-main" onClick={() => navigateTo({ url: `/pages/goal-detail/index?id=${g.id}` })}>
          <View className="goal-card-header">
            <View className="goal-card-name-row">
              <Text className="goal-card-name">{g.title}</Text>
              {isAchieved && <View className="goal-badge"><Icon name="award" size={28} color="accent" /></View>}
            </View>
            <Text className="goal-card-pct">{progressPct}%</Text>
          </View>
          <View className="goal-progress-bar">
            <View className={`goal-progress-fill ${isAchieved ? "completed" : ""}`} style={{ width: `${progressPct}%` }} />
          </View>
          <View className="goal-card-values">
            <Text>{g.currentValue} / {g.targetValue} {g.unit}</Text>
          </View>
          <View className="goal-card-meta">
            {g.linkedHabitsTotal > 0 && (
              <Text className="meta-tag">关联 {g.linkedHabitsCompleted}/{g.linkedHabitsTotal}</Text>
            )}
            {g.daysRemaining !== null && g.daysRemaining > 0 && (
              <Text className="meta-tag">剩余 {g.daysRemaining} 天</Text>
            )}
            {g.daysRemaining !== null && g.daysRemaining <= 0 && !isAchieved && (
              <Text className="meta-tag overdue">已逾期</Text>
            )}
            {isAchieved && (
              <Text className="meta-tag achieved-tag">已达成</Text>
            )}
          </View>
        </View>
        <View className="goal-card-actions">
          <Text className="action-btn" onClick={() => openEdit(g)}>编辑</Text>
          <Text className="action-btn danger" onClick={() => deleteGoal(g.id)}>删除</Text>
        </View>
      </View>
    );
  }

  if (loading) {
    return (
      <View className="page">
        <View className="page-header">
          <View>
            <Text className="page-title">目标管理</Text>
            <Text className="page-subtitle">管理你的阶段目标</Text>
          </View>
        </View>
        <View className="skeleton-lines">
          <View className="skeleton-line w-100" />
          <View className="skeleton-line w-80" />
          <View className="skeleton-line w-60" />
        </View>
      </View>
    );
  }

  return (
    <View className="page">
      <View className="page-header">
        <View>
          <Text className="page-title">目标管理</Text>
          <Text className="page-subtitle">管理你的阶段目标</Text>
        </View>
        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
      </View>

      {goals.length === 0 && (
        <View className="empty-section">
          <View className="empty-icon"><Icon name="target" size={64} color="muted" /></View>
          <Text className="empty-title">还没有目标</Text>
