      showToast({ title: "已更新", icon: "none" });
      setUpdateValue("");
      setUpdateNote("");
      fetchData();
    } catch {
      showToast({ title: "更新失败", icon: "none" });
    }
    setUpdating(false);
  }

  // ... render ...
}
