function getStepSize(unit: string): number {
  const weightUnits = ["kg", "lb", "斤", "公斤", "磅", "千克"];
  const timeUnits = ["分", "分钟", "min", "hour", "时", "小时"];
  const distanceUnits = ["km", "公里", "里", "mile", "英里"];
  if (weightUnits.includes(unit)) return 0.5;
  if (timeUnits.includes(unit)) return 5;
  if (distanceUnits.includes(unit)) return 0.5;
  return 1;
}
