import { useState } from "react";
import { View, Text, Input, Picker } from "@tarojs/components";
import { useDidShow, showModal, showToast, navigateTo } from "@tarojs/taro";
import { apiFetch } from "../../lib";
import Icon from "../../components/Icon";
import "./index.scss";

interface LinkedHabitInfo {
  id: string;
  title: string;
  completed: boolean;
}

interface Goal {
  id: string;
  title: string;
  description: string | null;
  startValue: number;
  targetValue: number;
  currentValue: number;
  unit: string;
  deadline: string | null;
  linkedHabitIds: string[];
  isArchived: boolean;
  createdAt: string;
  updatedAt: string;
  progress: number;
  daysRemaining: number | null;
  linkedHabits: LinkedHabitInfo[];
  linkedHabitsCompleted: number;
  linkedHabitsTotal: number;
}

interface HabitBrief {
  id: string;
  title: string;
  isActive: boolean;
}

interface GoalForm {
  title: string;
  description: string;
  startValue: string;
  targetValue: string;
  currentValue: string;
  unit: string;
  deadline: string;
  linkedHabitIds: string[];
}

interface AISuggestion {
  title: string;
  description: string;
  suggestedStartValue: number;
  suggestedTargetValue: number;
  unit: string;
  suggestedDeadlineDays: number;
}

export default function GoalsPage() {
  const [goals, setGoals] = useState<Goal[]>([]);
  const [habits, setHabits] = useState<HabitBrief[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [editId, setEditId] = useState<string | null>(null);
  const [form, setForm] = useState<GoalForm>({
    title: "", description: "", startValue: "", targetValue: "",
    currentValue: "", unit: "次", deadline: "", linkedHabitIds: [],
  });
  const [formDirty, setFormDirty] = useState(false);
  const [saving, setSaving] = useState(false);
  const [showAI, setShowAI] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiSuggestions, setAiSuggestions] = useState<AISuggestion[]>([]);

  useDidShow(() => {
    fetchGoals();
    fetchHabits();
  });

  async function fetchGoals() {
    try {
      setGoals(await apiFetch("/api/goals"));
    } catch {
      showToast({ title: "获取目标列表失败", icon: "none" });
    }
    setLoading(false);
  }

  async function fetchHabits() {
    try {
      const data = await apiFetch("/api/habits");
      setHabits(data.map((h: any) => ({ id: h.id, title: h.title, isActive: h.isActive })));
    } catch {
      // non-critical
    }
  }

  function openNew() {
    setEditId(null);
    setForm({ title: "", description: "", startValue: "", targetValue: "", currentValue: "", unit: "次", deadline: "", linkedHabitIds: [] });
    setFormDirty(false);
    setShowForm(true);
    setShowAI(false);
    setAiSuggestions([]);
  }

  function openEdit(g: Goal) {
    setEditId(g.id);
    setForm({
      title: g.title,
      description: g.description || "",
      startValue: String(g.startValue),
      targetValue: String(g.targetValue),
      currentValue: String(g.currentValue),
      unit: g.unit,
      deadline: g.deadline || "",
      linkedHabitIds: [...g.linkedHabitIds],
    });
    setFormDirty(false);
    setShowForm(true);
    setShowAI(false);
    setAiSuggestions([]);
  }

  function validateForm(): boolean {
    if (!form.title.trim()) {
      showToast({ title: "请输入目标名称", icon: "none" });
      return false;
    }
    const sv = parseFloat(form.startValue);
    const tv = parseFloat(form.targetValue);
    if (isNaN(sv)) { showToast({ title: "请输入有效的起始值", icon: "none" }); return false; }
    if (isNaN(tv)) { showToast({ title: "请输入有效的目标值", icon: "none" }); return false; }
    if (tv === sv) { showToast({ title: "目标值不能等于起始值", icon: "none" }); return false; }
    if (!form.unit.trim()) { showToast({ title: "请输入单位", icon: "none" }); return false; }
    return true;
  }

  async function handleSave() {
    if (!validateForm()) return;
    setSaving(true);
    try {
      const body: any = {
        title: form.title.trim(),
        description: form.description.trim() || null,
        startValue: parseFloat(form.startValue),
        targetValue: parseFloat(form.targetValue),
        unit: form.unit.trim(),
        linkedHabitIds: form.linkedHabitIds,
      };
      const cv = parseFloat(form.currentValue);
      if (!isNaN(cv)) body.currentValue = cv;
      if (form.deadline) body.deadline = form.deadline;

      if (editId) {
        await apiFetch("/api/goals", { method: "PUT", body: JSON.stringify({ id: editId, ...body }) });
      } else {
        await apiFetch("/api/goals", { method: "POST", body: JSON.stringify(body) });
      }
      setShowForm(false);
      setFormDirty(false);
      fetchGoals();
    } catch {
      showToast({ title: "保存目标失败", icon: "none" });
    } finally {
      setSaving(false);
    }
  }

  async function handleCloseForm() {
    if (formDirty) {
      const res = await showModal({ title: "确认关闭", content: "当前填写的内容尚未保存，确定要关闭吗？" });
      if (!res.confirm) return;
    }
    setShowForm(false);
  }

  async function deleteGoal(id: string) {
    const res = await showModal({ title: "确认删除", content: "删除后无法恢复，确定要删除此目标吗？" });
    if (!res.confirm) return;
    try {
      await apiFetch("/api/goals", { method: "DELETE", body: JSON.stringify({ id }) });
      fetchGoals();
    } catch {
      showToast({ title: "删除目标失败", icon: "none" });
    }
  }

  async function loadAIRecommendations() {
    setAiLoading(true);
    try {
      const data = await apiFetch("/api/goals/ai/suggestions?type=recommend");
      setAiSuggestions(data || []);
      setShowAI(true);
    } catch {
      showToast({ title: "获取AI推荐失败", icon: "none" });
    }
    setAiLoading(false);
  }

  function applyAISuggestion(s: AISuggestion) {
    setForm({
      title: s.title,
      description: s.description,
      startValue: String(s.suggestedStartValue),
      targetValue: String(s.suggestedTargetValue),
      currentValue: String(s.suggestedStartValue),
      unit: s.unit,
      deadline: "",
      linkedHabitIds: [],
    });
    setShowAI(false);
    setFormDirty(true);
  }

  function toggleLinkedHabit(habitId: string) {
    setForm(prev => ({
      ...prev,
      linkedHabitIds: prev.linkedHabitIds.includes(habitId)
        ? prev.linkedHabitIds.filter(id => id !== habitId)
        : [...prev.linkedHabitIds, habitId],
    }));
    setFormDirty(true);
  }

  const activeGoals = goals.filter(g => !g.isArchived && g.progress < 1);
  const achievedGoals = goals.filter(g => g.isArchived || g.progress >= 1);

  function renderGoalCard(g: Goal) {
    const isAchieved = g.progress >= 1;
    const progressPct = Math.min(Math.round(g.progress * 100), 100);

    return (
      <View key={g.id} className={`goal-card ${isAchieved ? "achieved" : ""}`}>
        <View className="goal-card-main" onClick={() => navigateTo({ url: `/pages/goal-detail/index?id=${g.id}` })}>
          <View className="goal-card-header">
            <View className="goal-card-name-row">
              <Text className="goal-card-name">{g.title}</Text>
              {isAchieved && <View className="goal-badge"><Icon name="award" size={28} color="accent" /></View>}
            </View>
            <Text className="goal-card-pct">{progressPct}%</Text>
          </View>
          <View className="goal-progress-bar">
            <View className={`goal-progress-fill ${isAchieved ? "completed" : ""}`} style={{ width: `${progressPct}%` }} />
          </View>
          <View className="goal-card-values">
            <Text>{g.currentValue} / {g.targetValue} {g.unit}</Text>
          </View>
          <View className="goal-card-meta">
            {g.linkedHabitsTotal > 0 && (
              <Text className="meta-tag">关联 {g.linkedHabitsCompleted}/{g.linkedHabitsTotal}</Text>
            )}
            {g.daysRemaining !== null && g.daysRemaining > 0 && (
              <Text className="meta-tag">剩余 {g.daysRemaining} 天</Text>
            )}
            {g.daysRemaining !== null && g.daysRemaining <= 0 && !isAchieved && (
              <Text className="meta-tag overdue">已逾期</Text>
            )}
            {isAchieved && (
              <Text className="meta-tag achieved-tag">已达成</Text>
            )}
          </View>
        </View>
        <View className="goal-card-actions">
          <Text className="action-btn" onClick={() => openEdit(g)}>编辑</Text>
          <Text className="action-btn danger" onClick={() => deleteGoal(g.id)}>删除</Text>
        </View>
      </View>
    );
  }

  if (loading) {
    return (
      <View className="page">
        <View className="page-header">
          <View>
            <Text className="page-title">目标管理</Text>
            <Text className="page-subtitle">管理你的阶段目标</Text>
          </View>
        </View>
        <View className="skeleton-lines">
          <View className="skeleton-line w-100" />
          <View className="skeleton-line w-80" />
          <View className="skeleton-line w-60" />
        </View>
      </View>
    );
  }

  return (
    <View className="page">
      <View className="page-header">
        <View>
          <Text className="page-title">目标管理</Text>
          <Text className="page-subtitle">管理你的阶段目标</Text>
        </View>
        <View className="add-btn" onClick={openNew}><Text>+</Text></View>
      </View>

      {goals.length === 0 && (
        <View className="empty-section">
          <View className="empty-icon"><Icon name="target" size={64} color="muted" /></View>
          <Text className="empty-title">还没有目标</Text>
          <Text className="empty-desc">设定一个目标，让习惯有方向</Text>
          <View className="empty-actions">
            <View className={`btn-ai ${aiLoading ? "loading" : ""}`} onClick={() => !aiLoading && loadAIRecommendations()}>
              <Icon name="bot" size={28} color="accent" />
              <Text>AI 推荐目标</Text>
            </View>
            <View className="btn-create" onClick={openNew}>
              <Text>手动创建</Text>
            </View>
          </View>
        </View>
      )}

      {activeGoals.length > 0 && (
        <View className="goal-section">
          <Text className="section-title">进行中</Text>
          {activeGoals.map(renderGoalCard)}
        </View>
      )}

      {achievedGoals.length > 0 && (
        <View className="goal-section">
          <Text className="section-title">已达成</Text>
          {achievedGoals.map(renderGoalCard)}
        </View>
      )}

      {/* ---- Goal Form Modal ---- */}
      {showForm && (
        <View className="modal-mask" onClick={handleCloseForm}>
          <View className="modal" onClick={(e) => e.stopPropagation()}>
            <Text className="modal-title">{editId ? "编辑目标" : "新增目标"}</Text>

            <View className="form-group">
              <Text className="form-label">目标名称</Text>
              <Input className="form-input" placeholder="如：减重 5kg" value={form.title} onInput={(e) => { setForm({ ...form, title: e.detail.value }); setFormDirty(true); }} />
              <View className="form-ai-btn" onClick={() => !editId && loadAIRecommendations()}>
                <Icon name="bot" size={24} color="accent" />
                <Text>AI 推荐</Text>
              </View>
            </View>

            <View className="form-group">
              <Text className="form-label">描述（选填）</Text>
              <Input className="form-input" placeholder="具体要达成什么" value={form.description} onInput={(e) => { setForm({ ...form, description: e.detail.value }); setFormDirty(true); }} />
            </View>

            <View className="form-row">
              <View className="form-group flex-1">
                <Text className="form-label">起始值</Text>
                <Input className="form-input" type="number" placeholder="0" value={form.startValue} onInput={(e) => { setForm({ ...form, startValue: e.detail.value }); setFormDirty(true); }} />
              </View>
              <View className="form-group flex-1">
                <Text className="form-label">目标值</Text>
                <Input className="form-input" type="number" placeholder="100" value={form.targetValue} onInput={(e) => { setForm({ ...form, targetValue: e.detail.value }); setFormDirty(true); }} />
              </View>
              <View className="form-group flex-1">
                <Text className="form-label">单位</Text>
                <Input className="form-input" placeholder="kg/次" value={form.unit} onInput={(e) => { setForm({ ...form, unit: e.detail.value }); setFormDirty(true); }} />
              </View>
            </View>

            <View className="form-group">
              <Text className="form-label">当前值（选填，默认等于起始值）</Text>
              <Input className="form-input" type="number" placeholder="可选" value={form.currentValue} onInput={(e) => { setForm({ ...form, currentValue: e.detail.value }); setFormDirty(true); }} />
            </View>

            <View className="form-group">
              <Text className="form-label">截止日期（选填）</Text>
              <Picker mode="date" value={form.deadline} onChange={(e) => { setForm({ ...form, deadline: e.detail.value }); setFormDirty(true); }}>
                <View className="form-picker">
                  <Text>{form.deadline || "选择日期"}</Text>
                </View>
              </Picker>
            </View>

            {habits.filter(h => h.isActive).length > 0 && (
              <View className="form-group">
                <Text className="form-label">关联习惯（可选）</Text>
                <View className="habit-checkbox-list">
                  {habits.filter(h => h.isActive).map(h => (
                    <View key={h.id} className="habit-checkbox-item" onClick={() => toggleLinkedHabit(h.id)}>
                      <View className={`checkbox ${form.linkedHabitIds.includes(h.id) ? "checked" : ""}`}>
                        {form.linkedHabitIds.includes(h.id) && <Icon name="check" size={24} color="accent" />}
                      </View>
                      <Text className="habit-checkbox-label">{h.title}</Text>
                    </View>
                  ))}
                </View>
              </View>
            )}

            <View className="form-buttons">
              <View className="btn-cancel" onClick={handleCloseForm}><Text>取消</Text></View>
              <View className={"btn-save" + (saving ? " disabled" : "")} onClick={() => !saving && handleSave()}><Text>{editId ? "保存" : "添加"}</Text></View>
            </View>
          </View>
        </View>
      )}

      {/* ---- AI Recommendations Overlay ---- */}
      {showAI && (
        <View className="modal-mask" onClick={() => setShowAI(false)}>
          <View className="modal ai-overlay" onClick={(e) => e.stopPropagation()}>
            <Text className="modal-title">AI 推荐目标</Text>
            {aiSuggestions.length === 0 ? (
              <Text className="ai-empty">暂无推荐，稍后再试</Text>
            ) : (
              <View className="ai-suggestion-list">
                {aiSuggestions.map((s, idx) => (
                  <View key={idx} className="ai-suggestion-card">
                    <View className="ai-suggestion-header">
                      <Icon name="bar-chart" size={32} color="accent" />
                      <Text className="ai-suggestion-title">{s.title}</Text>
                    </View>
                    <Text className="ai-suggestion-desc">{s.description}</Text>
                    <View className="ai-suggestion-detail">
                      <Text>{s.suggestedStartValue} → {s.suggestedTargetValue} {s.unit}</Text>
                      {s.suggestedDeadlineDays > 0 && <Text> · {s.suggestedDeadlineDays} 天期限</Text>}
                    </View>
                    <View className="ai-suggestion-apply" onClick={() => applyAISuggestion(s)}>
                      <Text>采纳此目标</Text>
                    </View>
                  </View>
                ))}
              </View>
            )}
            <View className="form-buttons">
              <View className="btn-cancel" onClick={() => setShowAI(false)}><Text>关闭</Text></View>
            </View>
          </View>
        </View>
      )}

      {goals.length > 0 && !loading && (
        <View className="manage-footer" onClick={() => navigateTo({ url: "/pages/goals/index" })} />
      )}
    </View>
  );
}

/* ============================================
   目标管理 - 天子日课
   ============================================ */

/* ---- 页面头部 ---- */
.page-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: var(--space-xl);
}

.add-btn {
  width: 72rpx;
  height: 72rpx;
  border-radius: var(--radius-full);
  background: var(--color-accent);
  color: var(--color-text-inverse);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 44rpx;
  font-weight: 300;
  line-height: 1;
  transition: opacity 0.2s;
}

.add-btn:active {
  opacity: 0.8;
}

/* ---- 分组标题 ---- */
.goal-section {
  margin-top: var(--space-xl);
}

.section-title {
  display: block;
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  margin-bottom: var(--space-md);
  padding-left: var(--space-md);
  border-left: 3rpx solid var(--color-accent);
}

/* ---- 目标卡片 ---- */
.goal-card {
  background: var(--color-card);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-md);
  margin-bottom: var(--space-sm);
  overflow: hidden;
  transition: all 0.2s ease;
  border-left: 6rpx solid var(--color-accent);
}

.goal-card:active {
  background: var(--color-card-hover);
}

.goal-card.achieved {
  border-left-color: #d4a05c;
  opacity: 0.8;
}

.goal-card-main {
  padding: var(--space-lg);
}

.goal-card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--space-md);
}

.goal-card-name-row {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex: 1;
  min-width: 0;
}

.goal-card-name {
  font-size: var(--text-md);
  font-weight: 500;
  color: var(--color-text-primary);
  letter-spacing: 0.02em;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.goal-badge {
  width: 44rpx;
  height: 44rpx;
  border-radius: var(--radius-full);
  background: rgba(212, 160, 92, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.goal-card-pct {
  font-size: var(--text-lg);
  font-weight: 700;
  color: var(--color-accent);
  flex-shrink: 0;
  margin-left: var(--space-md);
}

.goal-card.achieved .goal-card-pct {
  color: #d4a05c;
}

/* ---- 进度条 ---- */
.goal-progress-bar {
  width: 100%;
  height: 12rpx;
  border-radius: 6rpx;
  background: var(--color-border);
  overflow: hidden;
  margin-bottom: var(--space-md);
}

.goal-progress-fill {
  height: 100%;
  border-radius: 6rpx;
  background: var(--color-accent);
  transition: width 0.4s ease;
  min-width: 4rpx;
}

.goal-progress-fill.completed {
  background: #d4a05c;
}

/* ---- 数值文字 ---- */
.goal-card-values {
  font-size: var(--text-sm);
  color: var(--color-text-secondary);
  font-feature-settings: "tnum";
  margin-bottom: var(--space-sm);
}

/* ---- 元信息标签 ---- */
.goal-card-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-sm);
}

.meta-tag {
  font-size: var(--text-xs);
  color: var(--color-text-muted);
  background: var(--color-surface);
  padding: var(--space-xs) var(--space-sm);
  border-radius: var(--radius-xs);
  letter-spacing: 0.02em;
}

.meta-tag.overdue {
  color: var(--color-danger);
}

.meta-tag.achieved-tag {
  color: #d4a05c;
  background: rgba(212, 160, 92, 0.12);
}

/* ---- 卡片操作按钮 ---- */
.goal-card-actions {
  display: flex;
  align-items: center;
  gap: 4rpx;
  padding: 0 var(--space-lg) var(--space-md);
}

.goal-card-actions .action-btn {
  font-size: 22rpx;
  padding: 4rpx 10rpx;
  color: var(--color-text-muted);
  background: transparent;
  border: none;
  line-height: 1;
  transition: color 0.2s;
}

.goal-card-actions .action-btn:active {
  color: var(--color-accent);
}

.goal-card-actions .action-btn.danger {
  color: var(--color-danger);
}

.goal-card-actions .action-btn.danger:active {
  opacity: 0.8;
}

/* ---- 空状态 ---- */
.empty-section {
  text-align: center;
  padding: var(--space-2xl) 0;
  margin-top: var(--space-xl);
}

.empty-icon {
  margin-bottom: var(--space-lg);
}

.empty-title {
  display: block;
  font-size: var(--text-lg);
  font-weight: 500;
  color: var(--color-text-primary);
  margin-bottom: var(--space-sm);
}

.empty-desc {
  display: block;
  font-size: var(--text-sm);
