import { useState, useMemo } from "react";
import { View, Text, Input, ScrollView } from "@tarojs/components";
import { useDidShow, showToast, navigateBack, useRouter } from "@tarojs/taro";
import { apiFetch } from "../../lib";
import Icon from "../../components/Icon";
import "./index.scss";

interface LinkedHabitInfo {
  id: string;
  title: string;
  completed: boolean;
}

interface Goal {
  id: string;
  title: string;
  description: string | null;
  startValue: number;
  targetValue: number;
  currentValue: number;
  unit: string;
  deadline: string | null;
  linkedHabitIds: string[];
  isArchived: boolean;
  createdAt: string;
  updatedAt: string;
  progress: number;
  daysRemaining: number | null;
  linkedHabits: LinkedHabitInfo[];
  linkedHabitsCompleted: number;
  linkedHabitsTotal: number;
}

interface GoalLog {
  id: string;
  goalId: string;
  previousValue: number;
  newValue: number;
  delta: number;
  note: string | null;
  createdAt: string;
}

interface AISuggestion {
  trend: string;
  assessment: string;
  canMeetDeadline: boolean | null;
  suggestions: string[];
  adjustDeadline: boolean;
}

function getStepSize(unit: string): number {
  const weightUnits = ["kg", "lb", "斤", "公斤", "磅", "千克"];
  const timeUnits = ["分", "分钟", "min", "hour", "时", "小时", "minute"];
  const distanceUnits = ["km", "公里", "里", "mile", "英里"];
  if (weightUnits.includes(unit)) return 0.5;
  if (timeUnits.includes(unit)) return 5;
  if (distanceUnits.includes(unit)) return 0.5;
  return 1;
}

function getTrendColor(trend: string): string {
  switch (trend) {
    case "accelerating":
    case "on-track":
      return "var(--color-success)";
    case "slowing":
      return "var(--color-warning)";
    case "stuck":
      return "var(--color-danger)";
    default:
      return "var(--color-text-muted)";
  }
}

function getTrendLabel(trend: string): string {
  switch (trend) {
    case "accelerating": return "加速推进";
    case "on-track": return "按计划进行";
    case "slowing": return "进展放缓";
    case "stuck": return "进展停滞";
    default: return "数据不足";
  }
}

function formatLogDate(dateStr: string): string {
  const d = new Date(dateStr);
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const dd = String(d.getDate()).padStart(2, "0");
  return `${mm}/${dd}`;
}

export default function GoalDetailPage() {
  const router = useRouter();
  const goalId = router.params.id;

  const [goal, setGoal] = useState<Goal | null>(null);
  const [logs, setLogs] = useState<GoalLog[]>([]);
  const [aiSuggestion, setAiSuggestion] = useState<AISuggestion | null>(null);
  const [loading, setLoading] = useState(true);
  const [aiLoading, setAiLoading] = useState(true);
  const [updateValue, setUpdateValue] = useState("");
  const [updateNote, setUpdateNote] = useState("");
  const [updating, setUpdating] = useState(false);
  const [showManualInput, setShowManualInput] = useState(false);

  useDidShow(() => {
    if (goalId) {
      fetchData();
    }
  });

  async function fetchData() {
    setLoading(true);
    try {
      const goals = await apiFetch("/api/goals");
      const found = goals.find((g: any) => g.id === goalId);
      setGoal(found || null);

      const logsData = await apiFetch(`/api/goals/${goalId}/logs`);
      setLogs(logsData || []);
    } catch {
      showToast({ title: "加载目标详情失败", icon: "none" });
    }
    setLoading(false);
    fetchAISuggestions();
  }

  async function fetchAISuggestions() {
    setAiLoading(true);
    try {
      const data = await apiFetch(`/api/goals/ai/suggestions?type=progress&goalId=${goalId}`);
      setAiSuggestion(data);
    } catch {
      setAiSuggestion(null);
    }
    setAiLoading(false);
  }

  async function handleUpdateValue(delta?: number) {
    if (!goal) return;
    let newValue: number;
    if (delta !== undefined) {
      newValue = goal.currentValue + delta;
    } else {
      newValue = parseFloat(updateValue);
      if (isNaN(newValue)) {
        showToast({ title: "请输入有效数值", icon: "none" });
        return;
      }
    }

    setUpdating(true);
    try {
      await apiFetch("/api/goals", {
        method: "PUT",
        body: JSON.stringify({
          id: goalId,
          currentValue: newValue,
          note: updateNote || null,
        }),
      });
      showToast({ title: "已更新", icon: "none" });
      setUpdateValue("");
      setUpdateNote("");
      setShowManualInput(false);
      fetchData();
    } catch {
      showToast({ title: "更新失败", icon: "none" });
    }
    setUpdating(false);
  }

  const stepSize = useMemo(() => goal ? getStepSize(goal.unit) : 1, [goal]);

  if (loading) {
    return (
      <View className="page">
        <View className="back-header" onClick={() => navigateBack()}>
          <Text className="back-arrow">&#8249;</Text>
          <Text className="back-text">返回</Text>
        </View>
        <View className="skeleton-lines">
          <View className="skeleton-line w-100" />
          <View className="skeleton-line w-80" />
          <View className="skeleton-line w-60" />
        </View>
      </View>
    );
  }

  if (!goal) {
    return (
      <View className="page">
        <View className="back-header" onClick={() => navigateBack()}>
          <Text className="back-arrow">&#8249;</Text>
          <Text className="back-text">返回</Text>
        </View>
        <View className="empty">
          <Text>目标未找到</Text>
        </View>
      </View>
    );
  }

  const isAchieved = goal.progress >= 1;
  const progressPct = Math.min(Math.round(goal.progress * 100), 100);

  return (
    <View className="page">
      {/* ---- Back header ---- */}
      <View className="back-header" onClick={() => navigateBack()}>
        <Text className="back-arrow">&#8249;</Text>
        <Text className="back-text">{goal.title}</Text>
      </View>

      {/* ---- Progress Card ---- */}
      <View className={`detail-progress-card ${isAchieved ? "achieved" : ""}`}>
        <View className="detail-progress-header">
          <Text className="detail-progress-title">{goal.title}</Text>
          {isAchieved && (
            <View className="detail-achieved-badge">
              <Icon name="award" size={32} color="accent" />
              <Text>已达成</Text>
            </View>
          )}
        </View>

        <View className="detail-progress-bar-container">
          <View className="detail-progress-bar">
            <View className={`detail-progress-fill ${isAchieved ? "completed" : ""}`} style={{ width: `${progressPct}%` }} />
          </View>
          <Text className="detail-progress-pct">{progressPct}%</Text>
        </View>

        <View className="detail-progress-values">
          <Text className="detail-current-value">{goal.currentValue}</Text>
          <Text className="detail-value-sep">/</Text>
          <Text className="detail-target-value">{goal.targetValue}</Text>
          <Text className="detail-unit">{goal.unit}</Text>
        </View>

        <View className="detail-progress-meta">
          <Text className="meta-item">起始 {goal.startValue}{goal.unit}</Text>
          <Text className="meta-item">目标 {goal.targetValue}{goal.unit}</Text>
          {goal.deadline && (
            <Text className={`meta-item ${goal.daysRemaining !== null && goal.daysRemaining <= 0 ? "overdue" : ""}`}>
              截止 {goal.deadline}
              {goal.daysRemaining !== null && goal.daysRemaining > 0 && ` (剩 ${goal.daysRemaining} 天)`}
              {goal.daysRemaining !== null && goal.daysRemaining <= 0 && " (已逾期)"}
            </Text>
          )}
        </View>

        {/* ---- Quick Update ---- */}
        <View className="quick-update">
          <Text className="quick-update-label">更新数值</Text>
          <View className="quick-update-buttons">
            <View className="step-btn" onClick={() => !updating && handleUpdateValue(stepSize)}>+{stepSize}</View>
            <View className="step-btn secondary" onClick={() => !updating && handleUpdateValue(Math.round(stepSize * 2 > 1 ? Math.ceil(stepSize) : stepSize * 2))}>
              +{Math.round(stepSize * 2 > 1 ? Math.ceil(stepSize) : stepSize * 2)}
            </View>
            <View className="step-btn danger" onClick={() => !updating && handleUpdateValue(-stepSize)}>-{stepSize}</View>
            <View className="step-btn outline" onClick={() => setShowManualInput(!showManualInput)}>
              <Text>手动</Text>
            </View>
          </View>

          {showManualInput && (
            <View className="manual-update">
              <View className="manual-update-row">
                <Input
                  className="manual-input"
                  type="number"
                  placeholder="新数值"
                  value={updateValue}
                  onInput={(e) => setUpdateValue(e.detail.value)}
                />
                <View className={`manual-save ${updating ? "disabled" : ""}`} onClick={() => !updating && handleUpdateValue()}>
                  <Text>保存</Text>
                </View>
              </View>
              <Input
                className="manual-note"
                placeholder="备注（选填）"
                value={updateNote}
                onInput={(e) => setUpdateNote(e.detail.value)}
              />
            </View>
          )}
        </View>
      </View>

      {/* ---- Linked Habits ---- */}
      {goal.linkedHabits && goal.linkedHabits.length > 0 && (
        <View className="detail-section">
          <Text className="section-title">
            <Icon name="clipboard-list" size={28} color="accent" />
            <Text> 关联习惯 ({goal.linkedHabitsCompleted}/{goal.linkedHabitsTotal})</Text>
          </Text>
          <View className="linked-habits-list">
            {goal.linkedHabits.map(h => (
              <View key={h.id} className={`linked-habit-item ${h.completed ? "done" : ""}`}>
                <View className={`linked-habit-check ${h.completed ? "checked" : ""}`}>
                  {h.completed && <Icon name="check" size={24} color="accent" />}
                </View>
                <Text className="linked-habit-name">{h.title}</Text>
                <Text className="linked-habit-status">{h.completed ? "今日已完成" : "未完成"}</Text>
              </View>
            ))}
          </View>
        </View>
      )}

      {/* ---- AI Suggestions ---- */}
      <View className="detail-section">
        <View className="section-title-row">
          <Text className="section-title">
            <Icon name="lightbulb" size={28} color="accent" />
            <Text> AI 建议</Text>
          </Text>
          <View className="section-action" onClick={() => !aiLoading && fetchAISuggestions()}>
            <Text>刷新</Text>
          </View>
        </View>

        {aiLoading ? (
          <View className="skeleton-lines">
            <View className="skeleton-line w-80" />
            <View className="skeleton-line w-60" />
          </View>
        ) : aiSuggestion ? (
          <View className="ai-suggestion-box">
            <View className="ai-trend-row">
              <View className="trend-dot" style={{ backgroundColor: getTrendColor(aiSuggestion.trend) }} />
              <Text className="ai-trend-label" style={{ color: getTrendColor(aiSuggestion.trend) }}>
                {getTrendLabel(aiSuggestion.trend)}
              </Text>
              <Text className="ai-assessment">{aiSuggestion.assessment}</Text>
            </View>
            {aiSuggestion.suggestions.length > 0 && (
              <View className="ai-suggestions-list">
                {aiSuggestion.suggestions.map((s, idx) => (
                  <Text key={idx} className="ai-suggestion-item">{idx + 1}. {s}</Text>
                ))}
              </View>
            )}
          </View>
        ) : (
          <Text className="ai-fallback">数据不足，继续记录即可看到趋势</Text>
        )}
      </View>

      {/* ---- Progress Trend Chart (simplified CSS) ---- */}
      {logs.length >= 2 && (
        <View className="detail-section">
          <Text className="section-title">
            <Icon name="bar-chart" size={28} color="accent" />
            <Text> 进度趋势</Text>
          </Text>
          <View className="trend-chart">
            <View className="trend-values">
              {logs.slice(0, 10).reverse().map((log, idx) => {
                const maxVal = Math.max(goal.startValue, goal.targetValue, ...logs.map(l => l.newValue));
                const minVal = Math.min(goal.startValue, goal.targetValue, ...logs.map(l => l.newValue));
                const range = maxVal - minVal || 1;
                const heightPct = ((log.newValue - minVal) / range) * 100;
                return (
                  <View key={log.id} className="trend-bar-wrapper">
                    <View className="trend-bar" style={{ height: `${Math.max(heightPct, 5)}%` }} />
                    <Text className="trend-bar-label">{formatLogDate(log.createdAt)}</Text>
                  </View>
                );
              })}
            </View>
            <View className="trend-value-range">
              <Text className="trend-range-max">{Math.max(goal.startValue, ...logs.map(l => l.newValue))}{goal.unit}</Text>
              <Text className="trend-range-min">{Math.min(goal.targetValue, ...logs.map(l => l.newValue))}{goal.unit}</Text>
            </View>
          </View>
        </View>
      )}

      {/* ---- History Log ---- */}
      <View className="detail-section">
        <Text className="section-title">
          <Icon name="clipboard" size={28} color="accent" />
          <Text> 历史记录</Text>
        </Text>
        {logs.length === 0 ? (
          <Text className="log-empty">暂无记录</Text>
        ) : (
          <View className="log-list">
            {logs.map(log => (
              <View key={log.id} className="log-item">
                <View className="log-item-left">
                  <Text className="log-date">{formatLogDate(log.createdAt)}</Text>
                  <Text className="log-delta" style={{ color: log.delta < 0 ? "var(--color-success)" : log.delta > 0 ? "var(--color-accent)" : "var(--color-text-muted)" }}>
                    {log.delta > 0 ? "+" : ""}{log.delta}
                  </Text>
                </View>
                <View className="log-item-right">
                  <Text className="log-change">{log.previousValue} → {log.newValue} {goal.unit}</Text>
                  {log.note && <Text className="log-note">{log.note}</Text>}
                </View>
              </View>
            ))}
          </View>
        )}
      </View>
    </View>
  );
}

