  align-items: center;
  justify-content: center;
  font-size: var(--text-sm);
  color: var(--color-text-inverse);
  font-weight: 500;
  flex-shrink: 0;
  transition: opacity 0.2s;
}

.manual-save:active {
  opacity: 0.8;
}

.manual-save.disabled {
  opacity: 0.5;
}

.manual-note {
  width: 100%;
  height: 64rpx;
  border-radius: var(--radius-sm);
