  padding: 0 var(--space-md);
  font-size: var(--text-sm);
  color: var(--color-text-primary);
  margin-top: var(--space-sm);
  box-sizing: border-box;
}

/* ---- 区块通用 ---- */
.detail-section {
  background: var(--color-card);
