}

.section-action:active {
  opacity: 0.7;
}

/* ---- 关联习惯 ---- */
.linked-habits-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.linked-habit-item {
  display: flex;
  align-items: center;
  gap: var(--space-md);
  padding: var(--space-md);
