  border-radius: var(--radius-md);
  padding: var(--space-lg);
}

.ai-trend-row {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  margin-bottom: var(--space-md);
  flex-wrap: wrap;
}

.trend-dot {
  width: 16rpx;
  height: 16rpx;
  border-radius: 50%;
  flex-shrink: 0;
}

.ai-trend-label {
  font-size: var(--text-sm);
  font-weight: 600;
  letter-spacing: 0.02em;
}

.ai-assessment {
  font-size: var(--text-xs);
  color: var(--color-text-secondary);
