  min-width: 0;
}

.ai-suggestions-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.ai-suggestion-item {
  display: block;
  font-size: var(--text-xs);
  color: var(--color-text-secondary);
