  text-align: center;
  padding: var(--space-xl) 0;
}

/* ---- 进度趋势图 ---- */
.trend-chart {
  display: flex;
  gap: var(--space-md);
  align-items: flex-end;
  margin-top: var(--space-md);
}

.trend-values {
  flex: 1;
  display: flex;
  align-items: flex-end;
  gap: var(--space-sm);
  height: 140rpx;
  padding-bottom: 32rpx;
  position: relative;
}

.trend-bar-wrapper {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-end;
  height: 100%;
  position: relative;
}

.trend-bar {
  width: 100%;
  max-width: 32rpx;
  border-radius: 4rpx 4rpx 0 0;
  background: var(--color-accent);
  opacity: 0.7;
  transition: height 0.3s ease;
  min-height: 6rpx;
}

.trend-bar-label {
  position: absolute;
  bottom: 0;
  font-size: 18rpx;
  color: var(--color-text-muted);
  white-space: nowrap;
  text-align: center;
}

.trend-value-range {
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  padding-bottom: 32rpx;
  height: 140rpx;
  flex-shrink: 0;
}

.trend-range-max,
.trend-range-min {
  font-size: 18rpx;
  color: var(--color-text-muted);
  font-feature-settings: "tnum";
  line-height: 1;
}

/* ---- 历史记录 ---- */
.log-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.log-item {
  display: flex;
  align-items: flex-start;
  gap: var(--space-md);
  padding: var(--space-md);
  background: var(--color-surface);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-sm);
}

.log-item-left {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-xs);
  min-width: 64rpx;
  flex-shrink: 0;
}

.log-date {
  font-size: var(--text-xs);
  color: var(--color-text-muted);
  font-feature-settings: "tnum";
}

.log-delta {
  font-size: var(--text-sm);
  font-weight: 600;
  font-feature-settings: "tnum";
}

.log-item-right {
  flex: 1;
  min-width: 0;
}

.log-change {
  display: block;
  font-size: var(--text-sm);
  color: var(--color-text-primary);
  font-feature-settings: "tnum";
}

.log-note {
  display: block;
  font-size: var(--text-xs);
  color: var(--color-text-muted);
  margin-top: var(--space-xs);
}

.log-empty {
  display: block;
  text-align: center;
  padding: var(--space-xl);
  color: var(--color-text-muted);
  font-size: var(--text-sm);
}

/* ---- 骨架屏 ---- */
.skeleton-lines {
  display: flex;
  flex-direction: column;
  gap: var(--space-md);
  padding: var(--space-sm) 0;
}

.skeleton-line {
  height: 24rpx;
  border-radius: 12rpx;
  background: linear-gradient(
    90deg,
    var(--color-border) 25%,
    var(--color-border-light) 50%,
    var(--color-border) 75%
  );
  background-size: 200% 100%;
  animation: skeleton-shimmer 1.5s ease-in-out infinite;
}

.skeleton-line.w-100 {
  width: 100%;
}

.skeleton-line.w-80 {
  width: 80%;
}

.skeleton-line.w-60 {
  width: 60%;
}

@keyframes skeleton-shimmer {
  0% { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}

