function renderGoalProgressSection() {
  if (goalProgressLoading && goalProgressList.length === 0) {
    return (
      <View className="goals-progress-card">
        <View className="goals-progress-header">
          <Icon name="target" size={40} color="accent" />
          <Text className="goals-progress-title">目标进度</Text>
        </View>
        <View className="skeleton-lines">
          <View className="skeleton-line w-80" />
          <View className="skeleton-line w-60" />
        </View>
      </View>
    );
  }

  if (goalProgressError) {
    return (
      <View className="error-card">
        <Text className="error-card-text">目标数据加载失败</Text>
        <Text className="error-card-retry" onClick={fetchGoalProgress}>重试</Text>
      </View>
    );
  }

  const isEmpty = goalProgressList.length === 0;

  return (
    <View className="goals-progress-card">
      <View className="goals-progress-header" onClick={() => setGoalSectionCollapsed(!goalSectionCollapsed)}>
        <View className="goals-progress-header-left">
          <Icon name="target" size={40} color="accent" />
          <Text className="goals-progress-title">目标进度</Text>
          {!isEmpty && <Text className="goals-progress-count">{goalProgressList.length}</Text>}
        </View>
        <View className="goals-progress-header-right">
          {!isEmpty && (
            <Text className="goals-manage-link" onClick={(e) => { e.stopPropagation(); navigateTo({ url: "/pages/goals/index" }); }}>
              管理
            </Text>
          )}
          <Text className="goals-arrow">{goalSectionCollapsed ? "▼" : "▲"}</Text>
        </View>
      </View>
      <View className={`goals-progress-body ${goalSectionCollapsed ? "collapsed" : ""}`}>
        <View className="goals-progress-body-inner">
          {isEmpty ? (
            <View className="goals-empty">
              <Text className="goals-empty-text">还没有目标</Text>
              <Text className="goals-empty-desc">设定一个目标让习惯有方向</Text>
              <View className="goals-empty-actions">
                <View className="goals-empty-btn ai" onClick={() => navigateTo({ url: "/pages/goals/index" })}>
                  <Icon name="bot" size={24} color="accent" />
                  <Text>AI 推荐目标</Text>
                </View>
                <View className="goals-empty-btn manual" onClick={() => navigateTo({ url: "/pages/goals/index" })}>
                  <Text>手动创建</Text>
                </View>
              </View>
            </View>
          ) : (
            <View className="goals-progress-list">
              {goalProgressList.map((g) => {
                const isAchieved = g.progress >= 1;
                const progressPct = Math.min(Math.round(g.progress * 100), 100);
                const expanded = !!goalExpandedMap[g.id];

                return (
                  <View key={g.id} className={`goal-progress-item ${isAchieved ? "achieved" : ""}`}>
                    <View className="goal-progress-item-header" onClick={() => toggleGoalCardExpand(g.id)}>
                      <View className="goal-progress-item-title-row">
                        <Text className="goal-progress-item-name">{g.title}</Text>
                        {isAchieved && <View className="goal-progress-badge"><Icon name="award" size={24} color="accent" /></View>}
                      </View>
                      <Text className="goals-item-arrow">{expanded ? "▲" : "▼"}</Text>
                    </View>
                    <View className="goal-progress-bar">
                      <View className={`goal-progress-fill ${isAchieved ? "completed" : ""}`} style={{ width: `${progressPct}%` }} />
                    </View>
                    <View className="goal-progress-stats">
                      <Text className="goal-progress-values">{g.currentValue} / {g.targetValue} {g.unit}</Text>
                      <Text className="goal-progress-pct">{progressPct}%</Text>
                    </View>
                    <View className="goal-progress-meta">
                      {g.linkedHabitsTotal > 0 && (
                        <Text className="goal-progress-tag">关联习惯 {g.linkedHabitsCompleted}/{g.linkedHabitsTotal}</Text>
                      )}
                      {g.daysRemaining !== null && g.daysRemaining > 0 && (
                        <Text className="goal-progress-tag">剩余 {g.daysRemaining} 天</Text>
                      )}
                      {g.daysRemaining !== null && g.daysRemaining <= 0 && !isAchieved && (
                        <Text className="goal-progress-tag overdue">已逾期</Text>
                      )}
                    </View>
                    <View className={`goal-progress-expand-body ${expanded ? "" : "collapsed"}`}>
                      <View className="goal-progress-expand-inner">
                        <View className="goal-progress-quick-nav" onClick={() => navigateTo({ url: `/pages/goal-detail/index?id=${g.id}` })}>
                          <Text className="goal-progress-detail-link">查看详情 →</Text>
                        </View>
                      </View>
                    </View>
                  </View>
                );
              })}
            </View>
          )}
        </View>
      </View>
    </View>
  );
}

