/* ============================================
   目标进度卡片区块
   ============================================ */

.goals-progress-card {
  background: linear-gradient(135deg, var(--color-card) 0%, var(--color-surface) 100%);
  border: 1rpx solid var(--color-border);
  border-left: 6rpx solid var(--color-accent);
  border-radius: var(--radius-lg);
  padding: var(--space-lg);
  margin-top: var(--space-lg);
  position: relative;
  overflow: hidden;
}

.goals-progress-card::before {
  content: "";
  position: absolute;
  top: 0;
  left: 6rpx;
  right: 0;
  height: 1rpx;
  background: linear-gradient(90deg, var(--color-accent-subtle), transparent);
}

.goals-progress-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  cursor: pointer;
}

.goals-progress-header-left {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

.goals-progress-title {
  font-size: var(--text-md);
  font-weight: 600;
  color: var(--color-accent-light);
  letter-spacing: 0.03em;
}

.goals-progress-count {
  font-size: var(--text-xs);
  color: var(--color-text-muted);
  background: var(--color-border);
  padding: 2rpx 12rpx;
  border-radius: var(--radius-full);
  font-feature-settings: "tnum";
}

.goals-progress-header-right {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

.goals-manage-link {
  font-size: var(--text-xs);
  color: var(--color-accent);
  font-weight: 500;
  padding: var(--space-xs) var(--space-sm);
  border: 1rpx solid var(--color-accent-subtle);
  border-radius: var(--radius-sm);
  transition: opacity 0.2s;
}

.goals-manage-link:active {
  opacity: 0.7;
}

.goals-arrow {
  font-size: 20rpx;
  color: var(--color-text-muted);
  transition: transform 0.2s ease;
}

/* ---- 展开/收起动画 ---- */
.goals-progress-body {
  display: grid;
  grid-template-rows: 1fr;
  transition: grid-template-rows 0.25s ease-out;
  overflow: hidden;
  margin-top: var(--space-md);
}

.goals-progress-body.collapsed {
  grid-template-rows: 0fr;
}

.goals-progress-body-inner {
  min-height: 0;
  overflow: hidden;
}

.goals-progress-body.collapsed .goals-progress-body-inner {
  padding: 0;
}

/* ---- 空状态 ---- */
.goals-empty {
  text-align: center;
  padding: var(--space-xl) 0;
}

.goals-empty-text {
  display: block;
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  margin-bottom: var(--space-xs);
}

.goals-empty-desc {
  display: block;
  font-size: var(--text-xs);
  color: var(--color-text-muted);
  opacity: 0.7;
  margin-bottom: var(--space-lg);
}

.goals-empty-actions {
  display: flex;
  justify-content: center;
  gap: var(--space-md);
}

.goals-empty-btn {
  display: flex;
  align-items: center;
  gap: var(--space-xs);
  padding: var(--space-sm) var(--space-lg);
  border-radius: var(--radius-md);
  font-size: var(--text-xs);
  font-weight: 500;
  transition: opacity 0.2s;
}

.goals-empty-btn:active {
  opacity: 0.8;
}

.goals-empty-btn.ai {
  background: var(--color-accent-subtle);
  border: 1rpx solid var(--color-accent-subtle);
  color: var(--color-accent);
}

.goals-empty-btn.manual {
  border: 1rpx solid var(--color-border);
  color: var(--color-text-secondary);
}

/* ---- 目标进度条目 ---- */
.goals-progress-list {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.goal-progress-item {
  background: var(--color-card);
  border: 1rpx solid var(--color-border);
  border-radius: var(--radius-md);
  padding: var(--space-md);
  transition: border-color 0.2s;
  border-left: 4rpx solid var(--color-accent);
}

.goal-progress-item:active {
  border-color: var(--color-accent-subtle);
}

.goal-progress-item.achieved {
  border-left-color: #d4a05c;
}

.goal-progress-item-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: var(--space-sm);
  cursor: pointer;
}

.goal-progress-item-title-row {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex: 1;
  min-width: 0;
}

.goal-progress-item-name {
  font-size: var(--text-sm);
  font-weight: 500;
  color: var(--color-text-primary);
  letter-spacing: 0.02em;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.goal-progress-badge {
  width: 36rpx;
  height: 36rpx;
  border-radius: var(--radius-full);
  background: rgba(212, 160, 92, 0.15);
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

/* ---- 进度条 ---- */
.goal-progress-bar {
  width: 100%;
  height: 10rpx;
  border-radius: 5rpx;
  background: var(--color-border);
  overflow: hidden;
  margin-bottom: var(--space-sm);
}

.goal-progress-fill {
  height: 100%;
  border-radius: 5rpx;
  background: var(--color-accent);
  transition: width 0.4s ease;
  min-width: 4rpx;
}

.goal-progress-fill.completed {
  background: #d4a05c;
}

/* ---- 统计 ---- */
.goal-progress-stats {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: var(--space-xs);
}

.goal-progress-values {
  font-size: var(--text-xs);
  color: var(--color-text-secondary);
  font-feature-settings: "tnum";
}

.goal-progress-pct {
  font-size: var(--text-sm);
  font-weight: 600;
  color: var(--color-accent);
  font-feature-settings: "tnum";
}

.goal-progress-item.achieved .goal-progress-pct {
  color: #d4a05c;
}

/* ---- 标签 ---- */
.goal-progress-meta {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-xs);
}

.goal-progress-tag {
  font-size: 18rpx;
  color: var(--color-text-muted);
  background: var(--color-surface);
  padding: 2rpx 8rpx;
  border-radius: var(--radius-xs);
  letter-spacing: 0.02em;
}

.goal-progress-tag.overdue {
  color: var(--color-danger);
}

/* ---- 展开详情 ---- */
.goal-progress-expand-body {
  display: grid;
  grid-template-rows: 1fr;
  transition: grid-template-rows 0.2s ease-out;
  overflow: hidden;
}

.goal-progress-expand-body.collapsed {
  grid-template-rows: 0fr;
}

.goal-progress-expand-inner {
  min-height: 0;
  overflow: hidden;
  padding-top: var(--space-sm);
}

.goal-progress-quick-nav {
  margin-top: var(--space-xs);
}

.goal-progress-detail-link {
  font-size: var(--text-xs);
  color: var(--color-accent);
  font-weight: 500;
  transition: opacity 0.2s;
}

.goal-progress-detail-link:active {
  opacity: 0.7;
}

