8	interface Habit {
9	  id: string;
10	  title: string;
11	  description: string | null;
12	  domainId: string;
13	  unit: string;
14	  targetValue: number;
15	  isActive: boolean;
16	  logs?: { date: string; completed: boolean; value: number }[];
17	}
18	
19	interface DailyGoal {
20	  title: string;
21	  detail: string;
22	  reason: string;
23	}
24	
25	interface GoalProgress {
26	  id: string;
27	  title: string;
28	  startValue: number;
29	  targetValue: number;
30	  currentValue: number;
31	  unit: string;
32	  deadline: string | null;
33	  progress: number;
34	  daysRemaining: number | null;
35	  linkedHabitsCompleted: number;
36	  linkedHabitsTotal: number;
37	}
38	
39	export default function IndexPage() {
40	  const [habits, setHabits] = useState<Habit[]>([]);
41	  const [loading, setLoading] = useState(true);
42	  const [dailyGoals, setDailyGoals] = useState<DailyGoal[]>([]);
43	  const [goalsLoading, setGoalsLoading] = useState(false);
44	  const [goalsExpanded, setGoalsExpanded] = useState<Set<number>>(new Set());
45	  const [goalsDismissed, setGoalsDismissed] = useState(false);
46	  const [goalProgressList, setGoalProgressList] = useState<GoalProgress[]>([]);
47	  const [goalProgressLoading, setGoalProgressLoading] = useState(false);
48	  const [goalProgressError, setGoalProgressError] = useState(false);
49	  const [goalSectionCollapsed, setGoalSectionCollapsed] = useState(true);
50	  const [goalExpandedMap, setGoalExpandedMap] = useState<Record<string, boolean>>({});
51	
52	  useDidShow(() => {
53	    fetchHabits();
54	    checkDismissed();
55	    fetchDailyGoals();
56	    fetchGoalProgress();
57	  });
58	
59	  function checkDismissed() {
60	    const dismissedDate = Taro.getStorageSync("goals_dismissed_date");
61	    setGoalsDismissed(dismissedDate === getToday());
62	  }
63	
64	  async function fetchHabits() {
65	    try {
66	      const data = await apiFetch("/api/habits?date=" + getToday());
67	      setHabits(data);
68	    } catch {
69	      Taro.showToast({ title: "获取今日习惯失败", icon: "none" });
70	    }
71	    setLoading(false);
72	  }
73	
74	  async function fetchDailyGoals() {
75	    setGoalsLoading(true);
76	    try {
77	      const data = await apiFetch("/api/insights", {
78	        method: "POST",
79	        body: JSON.stringify({ type: "daily-goals" }),
80	      });
81	      setDailyGoals(data?.goals || []);
82	    } catch {
83	      setDailyGoals([]);
84	    }
85	    setGoalsLoading(false);
86	  }
87	
88	  async function fetchGoalProgress() {
89	    setGoalProgressLoading(true);
90	    setGoalProgressError(false);
91	    try {
92	      const data = await apiFetch("/api/goals");
93	      setGoalProgressList(data || []);
94	    } catch {
95	      setGoalProgressError(true);
96	    }
97	    setGoalProgressLoading(false);
98	  }
99	
100	  async function toggleHabit(habitId: string) {
101	    try {
102	      await apiFetch("/api/logs", {
103	        method: "POST",
104	        body: JSON.stringify({ habitId, date: getToday() }),
105	      });
106	      fetchHabits();
107	    } catch {
108	      Taro.showToast({ title: "打卡失败", icon: "none" });
109	    }
110	  }
111	
112	  function toggleGoalExpand(idx: number) {
113	    setGoalsExpanded((prev) => {
114	      const next = new Set(prev);
115	      if (next.has(idx)) {
116	        next.delete(idx);
117	      } else {
118	        next.add(idx);
119	      }
120	      return next;
121	    });
122	  }
123	
124	  function dismissGoals() {
125	    Taro.setStorageSync("goals_dismissed_date", getToday());
126	    setGoalsDismissed(true);
127	  }
128	
129	  function toggleGoalCardExpand(goalId: string) {
130	    setGoalExpandedMap((prev) => {
131	      const next = { ...prev };
132	      if (next[goalId]) {
133	        delete next[goalId];
134	      } else {
135	        next[goalId] = true;
136	      }
137	      return next;
138	    });
139	  }
140	
141	  const completedCount = habits.filter(
142	    (h) => h.logs?.length && h.logs[0]?.completed
143	  ).length;
144	  const totalCount = habits.filter((h) => h.isActive).length;
145	  const progressPct = totalCount > 0 ? Math.round((completedCount / totalCount) * 100) : 0;
146	
147	  function renderGoalsBlock() {
148	    if (goalsDismissed) return null;
149	    if (goalsLoading) {
150	      return (
151	        <View className="goals-card">
152	          <View className="goals-header">
153	            <Icon name="clipboard-list" size={40} color="accent" />
154	            <Text className="goals-title">今日建议目标</Text>
155	          </View>
156	          <View className="skeleton-lines">
157	            <View className="skeleton-line w-80" />
158	            <View className="skeleton-line w-60" />
159	          </View>
160	        </View>
161	      );
162	    }
163	    if (!dailyGoals || dailyGoals.length === 0) return null;
164	
165	    return (
166	      <View className="goals-card">
167	        <View className="goals-header">
168	          <Icon name="clipboard-list" size={40} color="accent" />
169	          <Text className="goals-title">今日建议目标</Text>
170	          <View className="goals-dismiss" onClick={dismissGoals}>
171	            <Icon name="x" size={32} />
172	          </View>
173	        </View>
174	        {dailyGoals.map((goal, idx) => {
175	          const expanded = goalsExpanded.has(idx);
176	          return (
177	            <View
178	              key={idx}
179	              className={`goals-item ${expanded ? "expanded" : ""}`}
180	              onClick={() => toggleGoalExpand(idx)}
181	            >
182	              <View className="goals-item-header">
183	                <Text className="goals-item-title">{goal.title}</Text>
184	                <Text className="goals-item-arrow">{expanded ? "▲" : "▼"}</Text>
185	              </View>
186	              <View className={`goals-item-body ${expanded ? "" : "collapsed"}`}>
187	                <View className="goals-item-body-inner">
188	                  <Text className="goals-item-detail">{goal.detail}</Text>
189	                  <Text className="goals-item-reason">理由：{goal.reason}</Text>
190	                </View>
191	              </View>
192	            </View>
193	          );
194	        })}
195	      </View>
196	    );
197	  }
198	
199	  function renderGoalProgressSection() {
200	    if (goalProgressLoading && goalProgressList.length === 0) {
201	      return (
202	        <View className="goals-progress-card">
203	          <View className="goals-progress-header">
204	            <Icon name="target" size={40} color="accent" />
205	            <Text className="goals-progress-title">目标进度</Text>
206	          </View>
207	          <View className="skeleton-lines">
208	            <View className="skeleton-line w-80" />
209	            <View className="skeleton-line w-60" />
210	          </View>
211	        </View>
212	      );
213	    }
214	
215	    if (goalProgressError) {
216	      return (
217	        <View className="error-card">
218	          <Text className="error-card-text">目标数据加载失败</Text>
219	          <Text className="error-card-retry" onClick={fetchGoalProgress}>重试</Text>
220	        </View>
221	      );
222	    }
223	
224	    const isEmpty = goalProgressList.length === 0;
225	
226	    return (
227	      <View className="goals-progress-card">
228	        <View className="goals-progress-header" onClick={() => setGoalSectionCollapsed(!goalSectionCollapsed)}>
229	          <View className="goals-progress-header-left">
230	            <Icon name="target" size={40} color="accent" />
231	            <Text className="goals-progress-title">目标进度</Text>
232	            {!isEmpty && <Text className="goals-progress-count">{goalProgressList.length}</Text>}
233	          </View>
234	          <View className="goals-progress-header-right">
235	            {!isEmpty && (
236	              <Text className="goals-manage-link" onClick={(e) => { e.stopPropagation(); navigateTo({ url: "/pages/goals/index" }); }}>
237	                管理
238	              </Text>
239	            )}
240	            <Text className="goals-arrow">{goalSectionCollapsed ? "▼" : "▲"}</Text>
241	          </View>
242	        </View>
243	        <View className={`goals-progress-body ${goalSectionCollapsed ? "collapsed" : ""}`}>
244	          <View className="goals-progress-body-inner">
245	            {isEmpty ? (
246	              <View className="goals-empty">
247	                <Text className="goals-empty-text">还没有目标</Text>
248	                <Text className="goals-empty-desc">设定一个目标让习惯有方向</Text>
249	                <View className="goals-empty-actions">
250	                  <View className="goals-empty-btn ai" onClick={() => navigateTo({ url: "/pages/goals/index" })}>
251	                    <Icon name="bot" size={24} color="accent" />
252	                    <Text>AI 推荐目标</Text>
253	                  </View>
254	                  <View className="goals-empty-btn manual" onClick={() => navigateTo({ url: "/pages/goals/index" })}>
255	                    <Text>手动创建</Text>
256	                  </View>
257	                </View>
258	              </View>
259	            ) : (
260	              <View className="goals-progress-list">
261	                {goalProgressList.map((g) => {
262	                  const isAchieved = g.progress >= 1;
263	                  const progressPct = Math.min(Math.round(g.progress * 100), 100);
264	                  const expanded = !!goalExpandedMap[g.id];
265	
266	                  return (
267	                    <View key={g.id} className={`goal-progress-item ${isAchieved ? "achieved" : ""}`}>
268	                      <View className="goal-progress-item-header" onClick={() => toggleGoalCardExpand(g.id)}>
269	                        <View className="goal-progress-item-title-row">
270	                          <Text className="goal-progress-item-name">{g.title}</Text>
271	                          {isAchieved && <View className="goal-progress-badge"><Icon name="award" size={24} color="accent" /></View>}
272	                        </View>
273	                        <Text className="goals-item-arrow">{expanded ? "▲" : "▼"}</Text>
274	                      </View>
275	                      <View className="goal-progress-bar">
276	                        <View className={`goal-progress-fill ${isAchieved ? "completed" : ""}`} style={{ width: `${progressPct}%` }} />
277	                      </View>
278	                      <View className="goal-progress-stats">
279	                        <Text className="goal-progress-values">{g.currentValue} / {g.targetValue} {g.unit}</Text>
280	                        <Text className="goal-progress-pct">{progressPct}%</Text>
281	                      </View>
282	                      <View className="goal-progress-meta">
283	                        {g.linkedHabitsTotal > 0 && (
284	                          <Text className="goal-progress-tag">关联习惯 {g.linkedHabitsCompleted}/{g.linkedHabitsTotal}</Text>
285	                        )}
286	                        {g.daysRemaining !== null && g.daysRemaining > 0 && (
287	                          <Text className="goal-progress-tag">剩余 {g.daysRemaining} 天</Text>
288	                        )}
289	                        {g.daysRemaining !== null && g.daysRemaining <= 0 && !isAchieved && (
290	                          <Text className="goal-progress-tag overdue">已逾期</Text>
291	                        )}
292	                      </View>
293	                      <View className={`goal-progress-expand-body ${expanded ? "" : "collapsed"}`}>
294	                        <View className="goal-progress-expand-inner">
295	                          <View className="goal-progress-quick-nav" onClick={() => navigateTo({ url: `/pages/goal-detail/index?id=${g.id}` })}>
296	                            <Text className="goal-progress-detail-link">查看详情 →</Text>
297	                          </View>
298	                        </View>
299	                      </View>
300	                    </View>
301	                  );
302	                })}
303	              </View>
304	            )}
305	          </View>
306	        </View>
307	      </View>
308	    );
309	  }
310	
311	  return (
312	    <View className="page">
313	      <Text className="header-date">{formatDate(new Date())}</Text>
314	      <Text className="header-title">今日日课</Text>
315	
316	      {renderGoalsBlock()}
317	
318	      {renderGoalProgressSection()}
319	
320	      {totalCount > 0 ? (
321	        <View className="progress-card">
322	          <View className="progress-ring">
323	            <View style={{
324	              width: "140rpx", height: "140rpx", borderRadius: "50%",
325	              background: `conic-gradient(var(--color-accent) ${progressPct * 3.6}deg, var(--color-border) 0deg)`,
326	              display: "flex", alignItems: "center", justifyContent: "center"
327	            }}>
328	              <View style={{
329	                width: "110rpx", height: "110rpx", borderRadius: "50%",
330	                background: "var(--color-card)", display: "flex", alignItems: "center", justifyContent: "center"
331	              }}>
332	                <Text className="progress-pct">{progressPct}%</Text>
333	              </View>
334	            </View>
335	          </View>
336	          <View className="progress-info">
337	            <Text className="progress-num">{completedCount}/{totalCount}</Text>
338	            <Text className="progress-label">今日已完成</Text>
339	          </View>
340	        </View>
341	      ) : (
342	        <View className="progress-card">
343	          <View className="progress-info">
344	            <Text className="progress-num">--</Text>
345	            <Text className="progress-label">添加习惯以查看进度</Text>
346	          </View>
347	        </View>
348	      )}
349	
350	      {getDomains().map((domain) => {
351	        const domainHabits = habits.filter((h) => h.domainId === domain.name && h.isActive);
352	        if (domainHabits.length === 0) return null;
353	        return (
354	          <View key={domain.name}>
355	            <View className="domain-title-row">
356	              <Icon name={domain.icon as IconName} size={36} color="accent" />
357	              <Text className="domain-title">{domain.name}</Text>
358	            </View>
359	            {domainHabits.map((habit) => {
360	              const done = !!(habit.logs?.length && habit.logs[0]?.completed);
361	              return (
362	                <View
363	                  key={habit.id}
364	                  className={`habit-item ${done ? "done" : ""}`}
365	                  onClick={() => toggleHabit(habit.id)}
366	                >
367	                  <View className={`check-icon ${done ? "checked" : ""}`}>
368	                    {done && <Icon name="check" size={32} color="accent" />}
369	                  </View>
370	                  <View className="habit-text">
371	                    <Text className={`habit-name ${done ? "done" : ""}`}>{habit.title}</Text>
372	                    {habit.description && <Text className="habit-desc">{habit.description}</Text>}
373	                  </View>
374	                  <Text className="habit-unit">{habit.targetValue}{habit.unit}</Text>
375	                </View>
376	              );
377	            })}
378	          </View>
379	        );
380	      })}
381	
382	      {totalCount === 0 && (
383	        <View className="empty">
384	          <Text>还没有习惯</Text>
385	          <Text>去「习惯」页面添加吧</Text>
386	        </View>
387	      )}
388	    </View>
389	  );
390	}
